#include <iostream>
#include <fstream>

int main()
{
    std::ifstream file("input.txt");
    if (!file.is_open())
    {
        std::cout << "Unable to open the input file" << std::endl;
        return 1;
    }

    std::string word;
    int count = 0;

    while (std::getline(file, word))
    {
        if (word == "example")
        {
            count++;
        }
    }

    std::cout << "Number of occurrences of 'example': " << count << std::endl;
    file.close();
    return 0;
}

def binary_search(arr, element):
    low = 0
    high = len(arr) - 1

    while low <= high:
        mid = (low + high) // 2
        if arr[mid] == element:
            return mid
        if arr[mid] < element:
            low = mid + 1
        else:
            high = mid - 1
    return -1

print(binary_search([1, 3, 5, 7], 5))

def common_elements(arr1, arr2):
    return [x for x in arr1 if x in arr2]

print(common_elements([1, 2, 3, 4, 5], [2, 3, 4, 5, 6]))
